import{_ as t,o as a,c as n,ag as i}from"./chunks/framework.CHQlKclR.js";const u=JSON.parse('{"title":"Integrated PID Tuner","description":"","frontmatter":{},"headers":[],"relativePath":"api/pid-tuner.md","filePath":"api/pid-tuner.md"}'),s={name:"api/pid-tuner.md"};function r(l,e,o,d,p,h){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="integrated-pid-tuner" tabindex="-1">Integrated PID Tuner <a class="header-anchor" href="#integrated-pid-tuner" aria-label="Permalink to &quot;Integrated PID Tuner&quot;">​</a></h1><p>Vortex includes a built-in live PID tuner that allows you to adjust constants on the fly using the V5 Controller and Brain screen. This eliminates the need for repeated code re-compilation during the tuning process.</p><h2 id="basic-usage" tabindex="-1">Basic Usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic Usage&quot;">​</a></h2><p>To use the tuner, you must call <code>pid_tuner_iterate()</code> within your <code>opcontrol()</code> loop or a dedicated background task.</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opcontrol</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    while</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        chassis.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opcontrol_tank</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        chassis.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pid_tuner_iterate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // Process tuner inputs</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">        pros</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">delay</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="controls-default" tabindex="-1">Controls (Default) <a class="header-anchor" href="#controls-default" aria-label="Permalink to &quot;Controls (Default)&quot;">​</a></h3><ul><li><strong>Arrow Keys (Controller)</strong>: Navigate between PID groups (Drive, Turn, Swing, etc.) and constants (P, I, D, Start I).</li><li><strong>A / B Buttons</strong>: Increase or decrease the selected constant.</li><li><strong>X Button</strong>: Toggle between simplified and full tuning modes.</li></ul><hr><h2 id="configuration-api" tabindex="-1">Configuration API <a class="header-anchor" href="#configuration-api" aria-label="Permalink to &quot;Configuration API&quot;">​</a></h2><h3 id="pid-tuner-enable-pid-tuner-disable" tabindex="-1"><code>pid_tuner_enable()</code> / <code>pid_tuner_disable()</code> <a class="header-anchor" href="#pid-tuner-enable-pid-tuner-disable" aria-label="Permalink to &quot;`pid_tuner_enable()` / `pid_tuner_disable()`&quot;">​</a></h3><p>Enables or disables the tuner logic. When disabled, <code>pid_tuner_iterate()</code> does nothing.</p><h3 id="pid-tuner-print-brain-set-bool-enable" tabindex="-1"><code>pid_tuner_print_brain_set(bool enable)</code> <a class="header-anchor" href="#pid-tuner-print-brain-set-bool-enable" aria-label="Permalink to &quot;`pid_tuner_print_brain_set(bool enable)`&quot;">​</a></h3><p>Toggles whether the tuner interface is displayed on the V5 Brain screen.</p><h3 id="pid-tuner-print-terminal-set-bool-enable" tabindex="-1"><code>pid_tuner_print_terminal_set(bool enable)</code> <a class="header-anchor" href="#pid-tuner-print-terminal-set-bool-enable" aria-label="Permalink to &quot;`pid_tuner_print_terminal_set(bool enable)`&quot;">​</a></h3><p>Toggles whether the current PID constants are printed to the PROS terminal after every adjustment.</p><h3 id="pid-tuner-full-enable-bool-enable" tabindex="-1"><code>pid_tuner_full_enable(bool enable)</code> <a class="header-anchor" href="#pid-tuner-full-enable-bool-enable" aria-label="Permalink to &quot;`pid_tuner_full_enable(bool enable)`&quot;">​</a></h3><ul><li><strong><code>false</code> (Simplified)</strong>: Syncs forward and backward constants. Tuning &quot;Drive P&quot; updates both forward and backward PID.</li><li><strong><code>true</code> (Full)</strong>: Allows independent tuning of forward and backward constants for asymmetrical robots.</li></ul><hr><h2 id="increment-settings" tabindex="-1">Increment Settings <a class="header-anchor" href="#increment-settings" aria-label="Permalink to &quot;Increment Settings&quot;">​</a></h2><p>You can customize how much each constant increases/decreases per button press.</p><h3 id="pid-tuner-increment-p-set-double-val" tabindex="-1"><code>pid_tuner_increment_p_set(double val)</code> <a class="header-anchor" href="#pid-tuner-increment-p-set-double-val" aria-label="Permalink to &quot;`pid_tuner_increment_p_set(double val)`&quot;">​</a></h3><p>Sets the step size for the Proportional (kP) constant. (Default: <code>0.1</code>).</p><h3 id="pid-tuner-increment-i-set-double-val" tabindex="-1"><code>pid_tuner_increment_i_set(double val)</code> <a class="header-anchor" href="#pid-tuner-increment-i-set-double-val" aria-label="Permalink to &quot;`pid_tuner_increment_i_set(double val)`&quot;">​</a></h3><p>Sets the step size for the Integral (kI) constant. (Default: <code>0.001</code>).</p><h3 id="pid-tuner-increment-d-set-double-val" tabindex="-1"><code>pid_tuner_increment_d_set(double val)</code> <a class="header-anchor" href="#pid-tuner-increment-d-set-double-val" aria-label="Permalink to &quot;`pid_tuner_increment_d_set(double val)`&quot;">​</a></h3><p>Sets the step size for the Derivative (kD) constant. (Default: <code>0.25</code>).</p><h3 id="pid-tuner-increment-start-i-set-double-val" tabindex="-1"><code>pid_tuner_increment_start_i_set(double val)</code> <a class="header-anchor" href="#pid-tuner-increment-start-i-set-double-val" aria-label="Permalink to &quot;`pid_tuner_increment_start_i_set(double val)`&quot;">​</a></h3><p>Sets the step size for the Integral Start threshold. (Default: <code>1.0</code>).</p>',28)])])}const b=t(s,[["render",r]]);export{u as __pageData,b as default};
